if (root['lap_times'] == null){
	root['lap_times'] = ''
	root['lap_count'] = 0
}


let thisLap = $prop('CompletedLaps')

if ( thisLap != root['lap_count']) {
	root['lap_count'] = thisLap
	//root['lap_times'] += str(root['lap_count']) + ': ' + $prop('LastLapTime') + '; '
	root['lap_times'] += root['lap_count'] + ': ' + $prop('LastLapTime') + '; '
}

return root['lap_times']
